// 1. ดึงข้อมูลพื้นฐาน
const webhookData = $("Webhook").first().json;
const profileData = $input.first().json;
const displayName = profileData.profile?.displayName || "คุณ";
const event = webhookData?.body?.events?.[0];

const messageType = event?.message?.type;
const text = event?.message?.text ? event.message.text.trim() : "";

let isHandled = false; 
let replyMessage = "";
let extractedData = {
    "ชื่อกิจกรรม": "",
    "วันที่": "",
    "เวลาเริ่ม": "",
    "เวลาสิ้นสุด": ""
};

// --- Helper: แปลงคำเลขไทย/คำบอกเวลา เป็นตัวเลข ---
function thaiNumToDigit(str) {
    const map = { 'หนึ่ง':1, 'สอง':2, 'สาม':3, 'สี่':4, 'ห้า':5, 'หก':6, 'เจ็ด':7, 'แปด':8, 'เก้า':9, 'สิบ':10, 'เที่ยง':12 };
    return map[str] || parseInt(str);
}

function parseTime(s) {
    if (!s) return "";
    s = s.trim();
    let digitalMatch = s.match(/([0-9]{1,2})[:.]([0-9]{1,2})/);
    if (digitalMatch) return `${digitalMatch[1].padStart(2, '0')}:${digitalMatch[2].padStart(2, '0')}`;

    let hour = 0;
    let minute = s.includes("ครึ่ง") ? 30 : 0;
    let numMatch = s.match(/(หนึ่ง|สอง|สาม|สี่|ห้า|หก|เจ็ด|แปด|เก้า|สิบ|[0-9]+)/);
    let n = numMatch ? thaiNumToDigit(numMatch[0]) : null;

    if (s.includes("เที่ยงคืน")) hour = 0;
    else if (s.includes("ทุ่ม")) hour = (n || 1) + 18;
    else if (s.includes("ตี")) hour = n || 1;
    else if (s.includes("บ่าย")) {
        hour = (n === 1 || n === null || s.includes("บ่ายโมง")) ? 13 : n + 12;
    } else if (s.includes("เย็น") || s.includes("โมงเย็น")) {
        hour = (n <= 6) ? n + 12 : n;
    } else if (s.includes("โมง")) {
        if (s.includes("เช้า")) hour = (n === 6) ? 6 : (n || 0);
        else if (n >= 1 && n <= 5) hour = n + 12; 
        else hour = n || 0;
    } else if (n !== null) hour = n;

    return `${hour.toString().padStart(2, '0')}:${minute.toString().padStart(2, '0')}`;
}

if (messageType !== "text") {
    replyMessage = `อลิซยังอ่านไฟล์ไม่ได้ค่ะคุณ ${displayName} รบกวนพิมพ์ข้อความน้า 🌸`;
    isHandled = true;
} else {
    // 1. ดักจับวันที่
    const datePattern = /(วันนี้|พรุ่งนี้|มะรืน|[0-9]{1,2}[/-][0-9]{1,2})/i;
    const hasDate = text.match(datePattern);

    // 2. ปรับ Regex หน่วยเวลา (รองรับ ตี 5, 5 โมง, บ่าย 3)
    const timeUnit = "(?:เที่ยงคืน|เที่ยง|บ่าย[\\s\\S]{0,2}(?:หนึ่ง|สอง|สาม|สี่|ห้า|หก|[0-9])?|(?:หนึ่ง|สอง|สาม|สี่|ห้า|หก|เจ็ด|แปด|เก้า|สิบ|[0-9]{1,2})\\s*(?:โมง|ทุ่ม|ตี|เย็น|เช้า)|(?:ตี|ทุ่ม|บ่าย|โมง)\\s*(?:หนึ่ง|สอง|สาม|สี่|ห้า|หก|เจ็ด|แปด|เก้า|สิบ|[0-9]{1,2})|[0-9]{1,2}[:.][0-9]{1,2})";
    const rangeRegex = new RegExp(`(${timeUnit})\\s*(?:ถึง|จนถึง|-)\\s*(${timeUnit})`, "i");
    const singleTimeRegex = new RegExp(timeUnit, "i");

    const hasRange = text.match(rangeRegex);
    const hasTime = text.match(singleTimeRegex);

    if (hasRange) {
        extractedData["เวลาเริ่ม"] = parseTime(hasRange[1]);
        extractedData["เวลาสิ้นสุด"] = parseTime(hasRange[2]);
    } else if (hasTime) {
        extractedData["เวลาเริ่ม"] = parseTime(hasTime[0]);
    }
    if (hasDate) extractedData["วันที่"] = hasDate[0];

    // 3. ทำความสะอาดชื่อกิจกรรม
    let subject = text;
    // ลบส่วนที่เป็น วันที่ และ เวลา ออกก่อน
    if (hasDate) subject = subject.replace(hasDate[0], "");
    if (hasRange) subject = subject.replace(hasRange[0], "");
    else if (hasTime) subject = subject.replace(hasTime[0], "");

    // ลบคำกริยาช่วยและคำเชื่อม
    const cleanRegex = /(จด|บันทึก|นัด|เตือนว่า|เตือน|บอกว่า|ช่วย|ให้หน่อย|ตอน|ช่วง|ว่า|มีนัด|มีประชุม|ต้องไป|ไป|ที่)/g;
    subject = subject.replace(cleanRegex, "").replace(/\s+/g, ' ').trim();

    extractedData["ชื่อกิจกรรม"] = subject || "ธุระของคุณ " + displayName;

    // ตรวจสอบความสมบูรณ์เพื่อส่งต่อให้ AI สรุปสวยๆ
    if (extractedData["เวลาเริ่ม"] && (hasDate || text.includes("วันนี้"))) {
        const timeInfo = extractedData["เวลาสิ้นสุด"] ? `${extractedData["เวลาเริ่ม"]} - ${extractedData["เวลาสิ้นสุด"]}` : extractedData["เวลาเริ่ม"];
        replyMessage = `รับทราบค่ะ! อลิซจดนัด "${extractedData["ชื่อกิจกรรม"]}" \n📅 วันที่: ${extractedData["วันที่"] || 'วันนี้'}\n⏰ เวลา: ${timeInfo} เรียบร้อยแล้วค่ะ ✨`;
        isHandled = false; // ส่งไปให้ AI Agent สรุปตาม System Prompt ที่เราตั้งไว้
    }
}

return { isHandled, replyMessage, extractedData, debugText: text, messageType };

// 1. ดึงข้อมูลจากทั้ง 2 แหล่ง (Scan Input และ AI Agent)
const jsData = $("Scan Input").first().json.extractedData;
const aiOutput = $("AI Agent").first().json.output || "";

// ฟังก์ชันช่วยสกัดข้อมูลจากข้อความที่ AI ตอบกลับ (ในกรณีที่ AI ช่วยเติมข้อมูลให้)
function extractFromAI(text) {
    const summaryMatch = text.match(/📌 ชื่อกิจกรรม:\s*([^\n]+)/);
    const dateMatch = text.match(/📅 วันที่:\s*([^\n]+)/);
    const startMatch = text.match(/⏰ เวลาเริ่ม:\s*([^\n]+)/);
    const endMatch = text.match(/⏰ เวลาสิ้นสุด:\s*([^\n]+)/);

    return {
        "ชื่อกิจกรรม": summaryMatch ? summaryMatch[1].trim() : "",
        "วันที่": dateMatch ? dateMatch[1].trim() : "",
        "เวลาเริ่ม": startMatch ? startMatch[1].trim() : "",
        "เวลาสิ้นสุด": endMatch ? endMatch[1].trim() : ""
    };
}

const aiData = extractFromAI(aiOutput);

// เลือกใช้ข้อมูล: ถ้า AI มีข้อมูลให้ใช้ AI ถ้าไม่มีให้ใช้จากโหนด Scan Input
const extracted = {
    "ชื่อกิจกรรม": aiData["ชื่อกิจกรรม"] || jsData["ชื่อกิจกรรม"] || "ไม่มีชื่อกิจกรรม",
    "วันที่": aiData["วันที่"] || jsData["วันที่"] || "วันนี้",
    "เวลาเริ่ม": aiData["เวลาเริ่ม"] || jsData["เวลาเริ่ม"] || "00:00",
    "เวลาสิ้นสุด": aiData["เวลาสิ้นสุด"] || jsData["เวลาสิ้นสุด"] || ""
};

// 2. ฟังก์ชันแปลงวันที่ภาษาไทย (วันนี้, พรุ่งนี้, มะรืน หรือ วว/ดด/ปป)
function convertThaiDate(dateStr) {
    const now = new Date();
    let targetDate = new Date(now);

    if (dateStr.includes('พรุ่งนี้')) {
        targetDate.setDate(now.getDate() + 1);
    } else if (dateStr.includes('มะรืน')) {
        targetDate.setDate(now.getDate() + 2);
    } else if (!dateStr || dateStr.includes('วันนี้')) {
        // วันนี้ (ไม่ต้องเปลี่ยน)
    } else {
        const parts = dateStr.match(/(\d+)[/\\-](\d+)[/\\-](\d+)/);
        if (parts) {
            const day = parseInt(parts[1]);
            const month = parseInt(parts[2]) - 1;
            let year = parseInt(parts[3]);
            if (year > 2500) year -= 543; // แปลง พ.ศ. เป็น ค.ศ.
            targetDate = new Date(year, month, day);
        }
    }
    return targetDate;
}

// 3. ฟังก์ชันรวมวันที่กับเวลา (HH:mm)
function combineDateTime(dateObj, timeStr) {
    const [hour, minute] = timeStr.split(':').map(Number);
    const dt = new Date(dateObj);
    dt.setHours(hour || 0, minute || 0, 0, 0);
    return dt;
}

// 🌟 4. เพิ่มการระบุ Timezone +07:00 สำหรับประเทศไทย
function toLocalISOString(date) {
    const pad = (num) => (num < 10 ? '0' : '') + num;

    // สร้าง String ในรูปแบบ YYYY-MM-DDTHH:mm:ss
    const isoStr = date.getFullYear() +
        '-' + pad(date.getMonth() + 1) +
        '-' + pad(date.getDate()) +
        'T' + pad(date.getHours()) +
        ':' + pad(date.getMinutes()) +
        ':' + pad(date.getSeconds());

    // ระบุ Offset ของประเทศไทย (+07:00) ต่อท้ายเสมอ
    return isoStr + "+07:00";
}

// --- เริ่มประมวลผล ---
const eventDate = convertThaiDate(extracted["วันที่"]);
const startDateTime = combineDateTime(eventDate, extracted["เวลาเริ่ม"]);

let endDateTime;
if (extracted["เวลาสิ้นสุด"] && extracted["เวลาสิ้นสุด"] !== "") {
    endDateTime = combineDateTime(eventDate, extracted["เวลาสิ้นสุด"]);
} else {
    // ถ้าไม่มีเวลาสิ้นสุด ให้ตั้งเป็น 1 ชั่วโมงหลังจากเวลาเริ่ม
    endDateTime = new Date(startDateTime.getTime() + 60 * 60 * 1000);
}

// ป้องกันกรณีเวลาจบ น้อยกว่าเวลาเริ่ม
if (endDateTime <= startDateTime) {
    endDateTime = new Date(startDateTime.getTime() + 60 * 60 * 1000);
}

return {
    summary: extracted["ชื่อกิจกรรม"],
    startISO: toLocalISOString(startDateTime),
    endISO: toLocalISOString(endDateTime)
};
